<template><ion-page><AppHeader /><ion-content class="vivid-page"><div class="page-shell profile"><div class="avatar">{{ initials }}</div><h1>{{ auth.user?.name }}</h1><p>{{ auth.user?.email }}</p><section class="vivid-card"><h2>Dados pessoais</h2><AppField v-model="profile.name" label="Nome" /><AppField v-model="profile.email" label="E-mail" type="email" /><button class="primary-button" @click="saveProfile">Salvar alterações</button></section><section class="vivid-card"><h2>Alterar senha</h2><PasswordField v-model="password.currentPassword" label="Senha atual" /><PasswordField v-model="password.newPassword" label="Nova senha" /><PasswordField v-model="confirmation" label="Confirmar nova senha" /><router-link to="/forgot-password">Esqueci minha senha</router-link><button class="secondary-button" @click="changePassword">Alterar senha</button></section><button class="logout" @click="logout">Encerrar sessão</button></div><BottomNav /></ion-content></ion-page></template>
<script setup lang="ts">import { computed,reactive,ref,onMounted } from 'vue';import { IonPage,IonContent,toastController } from '@ionic/vue';import { useRouter } from 'vue-router';import AppHeader from '@/components/AppHeader.vue';import BottomNav from '@/components/BottomNav.vue';import AppField from '@/components/AppField.vue';import PasswordField from '@/components/PasswordField.vue';import { useAuthStore } from '@/stores/auth';const auth=useAuthStore(),router=useRouter(),profile=reactive({name:'',email:''}),password=reactive({currentPassword:'',newPassword:''}),confirmation=ref('');const initials=computed(()=>auth.user?.name?.split(' ').map(x=>x[0]).slice(0,2).join('')||'ML');const notify=async(m:string,c='success')=>{const t=await toastController.create({message:m,color:c,duration:2200});t.present()};onMounted(()=>Object.assign(profile,{name:auth.user?.name||'',email:auth.user?.email||''}));const saveProfile=async()=>{await auth.updateProfile(profile);notify('Perfil atualizado')};const changePassword=async()=>{if(password.newPassword!==confirmation.value)return notify('As senhas não coincidem','warning');try{await auth.changePassword(password);await auth.clearBiometricLink();notify('Senha alterada. Ative a biometria novamente no próximo login')}catch(e:any){notify(e.response?.data?.message||'Erro ao alterar senha','danger')}};const logout=async()=>{await auth.logout();router.replace('/login')};</script>
<style scoped>.profile{text-align:center;padding-top:26px}.avatar{width:92px;height:92px;margin:auto;border-radius:50%;display:grid;place-items:center;font-size:30px;background:#684179;border:3px solid var(--vivid-primary-bright)}.profile h1{margin-bottom:4px}.profile>p{color:var(--vivid-muted)}section{text-align:left;padding:18px;margin:22px 0}section h2{font-size:18px}section a{display:block;color:var(--vivid-primary-bright);margin:8px 0 18px}.logout{width:100%;background:transparent;border:1px solid #ffb4ab;color:#ffb4ab;border-radius:12px;height:48px}</style>
